import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import orderService from '../services/orderService';
import './Download.css';

const Download = () => {
  const { user } = useContext(AuthContext);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [orderId, setOrderId] = useState('');
  const [filterOrderStatus, setFilterOrderStatus] = useState('');
  const [filterPaymentMethod, setFilterPaymentMethod] = useState('');

  useEffect(() => {
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      const data = await orderService.getAll();
      setOrders(data.filter(order => order.paymentStatus === 'paid'));
    } catch (error) {
      console.error('Error fetching orders:', error);
    }
  };

  const downloadReport = async (reportType) => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      let url = '';
      let filename = '';

      switch (reportType) {
        case 'daily':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/daily?date=${selectedDate}`;
          filename = `daily-report-${selectedDate}.pdf`;
          break;
        case 'weekly':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/weekly`;
          filename = 'weekly-report.pdf';
          break;
        case 'monthly':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/monthly`;
          filename = 'monthly-report.pdf';
          break;
        case 'cash':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/cash`;
          filename = 'cash-payment-report.pdf';
          break;
        case 'upi':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/upi`;
          filename = 'upi-payment-report.pdf';
          break;
        case 'card':
          url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/card`;
          filename = 'card-payment-report.pdf';
          break;
        default:
          break;
      }

      const response = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (response.ok) {
        const blob = await response.blob();
        const downloadUrl = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = downloadUrl;
        link.download = filename;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(downloadUrl);
      } else {
        alert('Failed to download report');
      }
    } catch (error) {
      console.error('Error downloading report:', error);
      alert('Error downloading report');
    } finally {
      setLoading(false);
    }
  };

  const downloadReceipt = async (orderIdInput) => {
    if (!orderIdInput) {
      alert('Please enter an order ID');
      return;
    }
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const url = `${process.env.REACT_APP_API_URL || 'http://localhost:5001/api'}/reports/order/${orderIdInput}/receipt`;

      const response = await fetch(url, {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (response.ok) {
        const blob = await response.blob();
        const downloadUrl = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = downloadUrl;
        link.download = `receipt-${orderIdInput}.pdf`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(downloadUrl);
      } else {
        alert('Failed to download receipt. Please check the order ID.');
      }
    } catch (error) {
      console.error('Error downloading receipt:', error);
      alert('Error downloading receipt');
    } finally {
      setLoading(false);
    }
  };

  const deleteOrder = async (orderIdToDelete) => {
    if (!window.confirm('Are you sure you want to delete this order?')) {
      return;
    }
    setLoading(true);
    try {
      await orderService.delete(orderIdToDelete);
      alert('Order deleted successfully');
      fetchOrders();
    } catch (error) {
      console.error('Error deleting order:', error);
      alert('Failed to delete order');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="download-page">
      <div className="download-container">
        <h1>Download Reports</h1>
        <p className="download-subtitle">Generate and download various sales and payment reports</p>

        <div className="date-selector">
          <label htmlFor="date">Select Date for Daily Report:</label>
          <input
            type="date"
            id="date"
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
          />
        </div>

        <div className="report-section">
          <h2>Sales Reports</h2>
          <div className="report-buttons">
            <button
              className="download-btn sales-btn"
              onClick={() => downloadReport('daily')}
              disabled={loading}
            >
              <span className="btn-icon">📅</span>
              Download Daily Report
            </button>
            <button
              className="download-btn sales-btn"
              onClick={() => downloadReport('weekly')}
              disabled={loading}
            >
              <span className="btn-icon">📆</span>
              Download Weekly Report
            </button>
            <button
              className="download-btn sales-btn"
              onClick={() => downloadReport('monthly')}
              disabled={loading}
            >
              <span className="btn-icon">📆</span>
              Download Monthly Report
            </button>
          </div>
        </div>

        <div className="report-section">
          <h2>Payment Reports</h2>
          <div className="report-buttons">
            <button
              className="download-btn cash-btn"
              onClick={() => downloadReport('cash')}
              disabled={loading}
            >
              <span className="btn-icon">💵</span>
              Total Cash Payment
            </button>
            <button
              className="download-btn upi-btn"
              onClick={() => downloadReport('upi')}
              disabled={loading}
            >
              <span className="btn-icon">📱</span>
              Total UPI Payment
            </button>
            <button
              className="download-btn card-btn"
              onClick={() => downloadReport('card')}
              disabled={loading}
            >
              <span className="btn-icon">💳</span>
              Total Card Payment
            </button>
          </div>
        </div>

        <div className="report-section">
          <h2>Download Order by ID</h2>
          <div className="order-id-input">
            <input
              type="text"
              placeholder="Enter Order ID"
              value={orderId}
              onChange={(e) => setOrderId(e.target.value)}
            />
            <button
              className="download-btn"
              onClick={() => downloadReceipt(orderId)}
              disabled={loading || !orderId}
            >
              Download Receipt
            </button>
          </div>
        </div>

        <div className="report-section">
          <h2>All Order Receipts</h2>
          <p className="section-description">Download individual order receipts/bills for all paid orders</p>
          <div className="orders-list">
            {orders.length === 0 ? (
              <p className="no-orders">No paid orders found</p>
            ) : (
              orders.map((order) => (
                <div key={order._id} className="order-item">
                  <div className="order-info">
                    <span className="order-number">#{order.orderNumber}</span>
                    <span className="order-date">
                      {new Date(order.createdAt).toLocaleDateString()}
                    </span>
                    <span className="order-amount">₹{order.totalAmount.toFixed(2)}</span>
                  </div>
                  <div className="order-actions">
                    <button
                      className="download-receipt-btn"
                      onClick={() => downloadReceipt(order._id)}
                      disabled={loading}
                    >
                      Download Receipt
                    </button>
                    {user.role === 'manager' && (
                      <button
                        className="delete-btn"
                        onClick={() => deleteOrder(order._id)}
                        disabled={loading}
                      >
                        Delete
                      </button>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>

        {loading && <div className="loading-overlay">Processing...</div>}
      </div>
    </div>
  );
};

export default Download;
